def removeInvalidParentheses(s):
    def isValid(x):
        cnt = 0
        for c in x:
            if c == '(': cnt += 1
            elif c == ')': cnt -= 1
            if cnt < 0: return False
        return cnt == 0
    q = {s}
    while q:
        valid = list(filter(isValid, q))
        if valid: return valid
        q = {x[:i] + x[i+1:] for x in q for i in range(len(x)) if x[i] in '()'}

